import pathlib
import re

import pytest

AC_UID = "ac06_spec_append"
AC_TYPE = "data"

REPO_ROOT = pathlib.Path(__file__).resolve().parents[3]
SPEC_FILE = REPO_ROOT / "docs" / "dev" / "specs" / "spec-20260518-225715.md"
SOURCES = [
    REPO_ROOT / "docs" / "dev" / "completion-20260524-172805.md",
    REPO_ROOT / "docs" / "dev" / "completion-20260524-205206.md",
    REPO_ROOT / "docs" / "dev" / "completion-20260525-095242.md",
]

REQUIRED_HEADERS = ["### Cycle 4", "### Cycle 5", "### Cycle 6"]


def _content_below_header(spec_text, header):
    """Return the text block beneath `header` up to the next ### or end-of-file.

    Used to assert at least one line of non-empty implementation summary
    exists beneath each Cycle N header per AC-06.then.
    """
    idx = spec_text.find(header)
    if idx == -1:
        return None
    after_header = spec_text[idx + len(header):]
    # Strip leading newline + advance to body start.
    after_header = after_header.lstrip("\n")
    # Find next ### header at same level; truncate.
    next_match = re.search(r"^### ", after_header, flags=re.MULTILINE)
    if next_match:
        return after_header[: next_match.start()]
    return after_header


def test_AC_06_spec_append_cycle_4_5_6_present_with_content():
    """
    GIVEN: docs/dev/specs/spec-20260518-225715.md exists with Cycle 1/2/3
           content.
    WHEN:  dev appends Cycle 4/5/6 sections from completion-20260524-172805.md,
           completion-20260524-205206.md, completion-20260525-095242.md.
    THEN:  spec Sections 2-8 contain ### Cycle 4, ### Cycle 5, ### Cycle 6
           headers with NON-EMPTY content beneath each header sourced from
           the three completion reports. Each cycle header must have at
           least one line of implementation summary.
    """
    assert SPEC_FILE.exists(), f"spec file missing at {SPEC_FILE}"
    for src in SOURCES:
        assert src.exists(), f"source completion report missing: {src}"

    spec_text = SPEC_FILE.read_text(encoding="utf-8")

    for header in REQUIRED_HEADERS:
        assert header in spec_text, (
            f"required header {header!r} not found in {SPEC_FILE}"
        )
        body = _content_below_header(spec_text, header)
        assert body is not None, f"could not locate body beneath {header!r}"
        # At least one non-empty line of content beneath the header.
        nonempty_lines = [
            ln for ln in body.splitlines()
            if ln.strip() and not ln.strip().startswith("#")
        ]
        assert nonempty_lines, (
            f"header {header!r} has no implementation summary content "
            f"beneath it (only whitespace/comments)."
        )
